class StudentProgressTracker:
    def __init__(self):
        self.students = {}

    def add_student(self, name):
        self.students[name] = {"points": 0, "assignments_completed": 0}

    def complete_assignment(self, name):
        if name in self.students:
            self.students[name]["points"] += 10
            self.students[name]["assignments_completed"] += 1
        else:
            print(f"Student {name} not found.")

    def get_leaderboard(self):
        sorted_students = sorted(self.students.items(), key=lambda x: x[1]["points"], reverse=True)
        return sorted_students

# Example usage
classroom = StudentProgressTracker()
classroom.add_student("Alice")
classroom.add_student("Bob")
classroom.add_student("Charlie")

# Simulate assignment completions
classroom.complete_assignment("Alice")
classroom.complete_assignment("Alice")
classroom.complete_assignment("Bob")

# Display leaderboard
leaderboard = classroom.get_leaderboard()
print("Leaderboard:")
for rank, (name, data) in enumerate(leaderboard, 1):
    print(f"{rank}. {name}: {data['points']} points, {data['assignments_completed']} assignments completed")


This script tracks student progress by assigning points for completed assignments and generates a leaderboard. Teachers can extend it by adding features like badges, levels, or customizable reward systems.
